// Generated by OrchestKit Claude Plugin
// Created: 2026-05-06

/**
 * ASCII Lint — PostToolUse warn-only linter for fenced ASCII blocks in *.md.
 * Implements 5 rules from designs/ascii-design-system.md §A.3.
 * Severity is locked to `warn` (D3); never blocks an Edit/Write.
 *
 * Per-rule disable directive (place on a line preceding the fenced block):
 *   <!-- ascii-lint-disable: width-80,single-set -->
 */

import { existsSync, readFileSync } from 'node:fs';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getField } from '../lib/common.js';
import { safeProjectDir } from '../lib/paths.js';
import { NOOP_CTX } from '../lib/context.js';

const SETS = {
  default:  { corners: '┌┐└┘', edges: '─│', junctions: '┬┴├┤┼' },
  emphasis: { corners: '┏┓┗┛', edges: '━┃', junctions: '┳┻┣┫╋' },
  title:    { corners: '╔╗╚╝', edges: '═║', junctions: '╦╩╠╣╬' },
  soft:     { corners: '╭╮╰╯', edges: '─│', junctions: '┬┴├┤┼' },
} as const;

const BOX_DRAWING = /[─-╿]/g;
const UNICODE_ARROW = /[→←↑↓]/;
const ASCII_ARROW = /->|<-|─>/;
const DENSITY_THRESHOLD = 0.20;
const MAX_FINDINGS_REPORTED = 10;

interface FencedBlock {
  startLine: number;
  lines: string[];
  raw: string;
  disabled: Set<string>;
}

interface Finding {
  block: FencedBlock;
  rule: string;
  message: string;
}

function extractFencedBlocks(content: string): FencedBlock[] {
  const lines = content.split('\n');
  const blocks: FencedBlock[] = [];
  let inBlock = false;
  let current: string[] = [];
  let startLine = 0;
  let pendingDisable = new Set<string>();

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (!inBlock) {
      const m = line.match(/<!--\s*ascii-lint-disable:\s*([\w,\s-]+)\s*-->/);
      if (m) {
        for (const r of m[1].split(',')) pendingDisable.add(r.trim());
      }
      if (/^```/.test(line)) {
        inBlock = true;
        startLine = i + 1;
        current = [];
      }
    } else {
      if (/^```/.test(line)) {
        const raw = current.join('\n');
        const boxCount = (raw.match(BOX_DRAWING) || []).length;
        if (boxCount >= 3) {
          blocks.push({ startLine, lines: current, raw, disabled: new Set(pendingDisable) });
        }
        inBlock = false;
        pendingDisable = new Set();
      } else {
        current.push(line);
      }
    }
  }
  return blocks;
}

function checkWidth(block: FencedBlock): Finding | null {
  for (let i = 0; i < block.lines.length; i++) {
    if (block.lines[i].length > 80) {
      return {
        block,
        rule: 'width-80',
        message: `line ${block.startLine + i}: width ${block.lines[i].length} > 80`,
      };
    }
  }
  return null;
}

function classifySet(text: string): string[] {
  const found: string[] = [];
  const cornerHits: Record<string, boolean> = {};
  for (const [name, def] of Object.entries(SETS)) {
    let matched = false;
    for (const ch of def.corners) {
      if (text.includes(ch)) { matched = true; cornerHits[name] = true; break; }
    }
    if (matched) { found.push(name); continue; }
    for (const ch of def.edges) {
      if (text.includes(ch)) { matched = true; break; }
    }
    if (matched) found.push(name);
  }
  // default and soft share edges; if only the shared edge matched, prefer the one whose corners are present
  if (found.includes('default') && found.includes('soft')) {
    if (cornerHits.default && !cornerHits.soft) {
      found.splice(found.indexOf('soft'), 1);
    } else if (cornerHits.soft && !cornerHits.default) {
      found.splice(found.indexOf('default'), 1);
    }
  }
  return found;
}

function checkSingleSet(block: FencedBlock): Finding | null {
  const sets = classifySet(block.raw);
  if (sets.length > 1) {
    return {
      block,
      rule: 'single-set',
      message: `mixes glyphs from sets: ${sets.join(', ')} (use one set per block)`,
    };
  }
  return null;
}

const CORNER_GROUPS: ReadonlyArray<[string, string, string, string]> = [
  ['┌', '┐', '└', '┘'],
  ['┏', '┓', '┗', '┛'],
  ['╔', '╗', '╚', '╝'],
  ['╭', '╮', '╰', '╯'],
];

function countChar(text: string, ch: string): number {
  let n = 0;
  for (const c of text) if (c === ch) n++;
  return n;
}

function checkBalancedCorners(block: FencedBlock): Finding | null {
  for (const [tl, tr, bl, br] of CORNER_GROUPS) {
    const tlc = countChar(block.raw, tl);
    const trc = countChar(block.raw, tr);
    const blc = countChar(block.raw, bl);
    const brc = countChar(block.raw, br);
    if (tlc + trc + blc + brc === 0) continue;
    if (!(tlc === trc && blc === brc && tlc === blc)) {
      return {
        block,
        rule: 'balanced-corners',
        message: `unbalanced ${tl}=${tlc} ${tr}=${trc} ${bl}=${blc} ${br}=${brc}`,
      };
    }
  }
  return null;
}

function checkSingleArrowStyle(block: FencedBlock): Finding | null {
  const styles: string[] = [];
  if (UNICODE_ARROW.test(block.raw)) styles.push('unicode');
  if (ASCII_ARROW.test(block.raw)) styles.push('ascii');
  if (styles.length > 1) {
    return {
      block,
      rule: 'single-arrow-style',
      message: `mixes arrow styles: ${styles.join(' + ')}`,
    };
  }
  return null;
}

function checkDensity(block: FencedBlock): Finding | null {
  const text = block.raw;
  const info = (text.match(/[A-Za-z0-9→←↑↓]/g) || []).length;
  const boxes = (text.match(BOX_DRAWING) || []).length;
  const ws = (text.match(/\s/g) || []).length;
  const total = info + boxes + ws;
  if (total === 0) return null;
  const density = info / total;
  if (density < DENSITY_THRESHOLD) {
    return {
      block,
      rule: 'density-min',
      message: `density ${density.toFixed(2)} < ${DENSITY_THRESHOLD} (too decorative)`,
    };
  }
  return null;
}

const RULES: Array<[string, (b: FencedBlock) => Finding | null]> = [
  ['width-80',           checkWidth],
  ['single-set',         checkSingleSet],
  ['balanced-corners',   checkBalancedCorners],
  ['single-arrow-style', checkSingleArrowStyle],
  ['density-min',        checkDensity],
];

export function asciiLint(input: HookInput, _ctx: HookContext = NOOP_CTX): HookResult {
  try {
    const tool = input.tool_name || '';
    if (tool !== 'Write' && tool !== 'Edit' && tool !== 'MultiEdit') {
      return outputSilentSuccess();
    }

    const filePath = getField<string>(input, 'tool_input.file_path') || '';
    if (!filePath.endsWith('.md')) return outputSilentSuccess();
    if (!filePath.includes('/src/')) return outputSilentSuccess();
    if (filePath.includes('/node_modules/') || filePath.includes('/.git/')) {
      return outputSilentSuccess();
    }

    const projectDir = safeProjectDir();
    const fullPath = filePath.startsWith('/') ? filePath : `${projectDir}/${filePath}`;
    if (!existsSync(fullPath)) return outputSilentSuccess();

    const content = readFileSync(fullPath, 'utf-8');
    const blocks = extractFencedBlocks(content);
    if (blocks.length === 0) return outputSilentSuccess();

    const findings: Finding[] = [];
    for (const block of blocks) {
      for (const [rule, check] of RULES) {
        if (block.disabled.has(rule)) continue;
        const f = check(block);
        if (f) findings.push(f);
      }
    }

    if (findings.length === 0) return outputSilentSuccess();

    const lines = findings
      .slice(0, MAX_FINDINGS_REPORTED)
      .map((f) => `  ⚠ L${f.block.startLine}: [${f.rule}] ${f.message}`);
    const more = findings.length > MAX_FINDINGS_REPORTED
      ? `\n  ...and ${findings.length - MAX_FINDINGS_REPORTED} more`
      : '';
    const fileName = filePath.split('/').pop();
    return {
      continue: true,
      systemMessage:
        `ascii-lint: ${findings.length} finding(s) in ${fileName}\n` +
        lines.join('\n') + more +
        `\n  (warn-only; disable per block: <!-- ascii-lint-disable: <rule> -->)`,
    };
  } catch {
    // silent: fail-open (lint must never block author flow)
    return outputSilentSuccess();
  }
}
